187	// ExecutionCleanupManager owns conservative reclamation of DDx temp execution
188	// resources for one project.
189	type ExecutionCleanupManager struct {
190		ProjectRoot     string
191		TempRoot        string
192		ScratchRoots    []string
193		ScratchPrefixes []string
194		ScratchMinAge   time.Duration
195		GitOps          GitOps
196		DryRun          bool
197		Now             func() time.Time
198		Probe           ExecutionCleanupLivenessProbe
199		// RetainDays controls how many days of evidence dirs under
200		// .ddx/executions/ to retain. 0 disables the prune; default is 90.
201		RetainDays int
202	}
