204	// NewExecutionCleanupManager constructs a cleanup manager with the default
205	// DDx temp worktree root and the default liveness probe.
206	func NewExecutionCleanupManager(projectRoot string, gitOps GitOps) *ExecutionCleanupManager {
207		return &ExecutionCleanupManager{
208			ProjectRoot: projectRoot,
209			TempRoot:    executionCleanupTempRoot(projectRoot),
210			RetainDays:  executionCleanupRetainDays(projectRoot),
211			GitOps:      gitOps,
212			Now:         time.Now,
213			Probe:       defaultExecutionCleanupLivenessProbe{},
214		}
215	}
216	
217	// executionCleanupRetainDays returns the configured retain_days for evidence
218	// dirs, defaulting to defaultEvidenceRetainDays when not set in config.
219	func executionCleanupRetainDays(projectRoot string) int {
220		if projectRoot != "" {
221			projectConfig := ddxroot.JoinProject(projectRoot, "config.yaml")
222			cfg, err := config.LoadFromFile(projectConfig)
223			if err == nil && cfg != nil && cfg.Executions != nil {
224				return cfg.Executions.ResolveRetainDays()
225			}
226		}
227		return defaultEvidenceRetainDays
228	}
