845			if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
846				return &states[i]
847			}
848			if meta.WorktreePath != "" && state.WorktreePath != "" && filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath) {
849				return &states[i]
850			}
851		}
852		return nil
853	}
