934			}
935		}
936	
937		var bytes int64
938		present := false
939		if info, statErr := os.Stat(path); statErr == nil {
940			present = true
941			bytes = info.Size()
942		} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
943			path = runStatePath(m.ProjectRoot)
944			if info, legacyErr := os.Stat(path); legacyErr == nil {
945				present = true
946				bytes = info.Size()
947				clear = func() error {
948					return ClearRunState(m.ProjectRoot)
949				}
950			}
951		}
952		if !m.DryRun {
