997	func (m *ExecutionCleanupManager) cleanupDurableLandedCandidateRefs(summary *ExecutionCleanupSummary) {
998		if m == nil || m.GitOps == nil || m.ProjectRoot == "" {
999			return
1000		}
1001		resultRoot := executeBeadArtifactRoot(m.ProjectRoot)
1002		entries, err := os.ReadDir(resultRoot)
1003		if err != nil {
1004			return
1005		}
1006		seen := map[string]struct{}{}
1007		for _, entry := range entries {
1008			if !entry.IsDir() {
1009				continue
1010			}
1011			resultPath := filepath.Join(resultRoot, entry.Name(), "result.json")
1012			data, readErr := os.ReadFile(resultPath)
1013			if readErr != nil {
1014				continue
1015			}
1016			var meta candidateRefResultMetadata
1017			if err := json.Unmarshal(data, &meta); err != nil {
1018				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1019					Path:    resultPath,
1020					Class:   "candidate_ref_result_parse",
1021					Message: err.Error(),
1022				})
1023				continue
1024			}
1025			if !candidateRefResultDurable(meta) {
1026				continue
1027			}
1028			if _, ok := seen[meta.CandidateRef]; ok {
1029				continue
1030			}
1031			seen[meta.CandidateRef] = struct{}{}
1032			if _, err := m.GitOps.ResolveRev(m.ProjectRoot, meta.CandidateRef); err != nil {
1033				continue
1034			}
1035			if !m.DryRun {
1036				if err := m.GitOps.DeleteRef(m.ProjectRoot, meta.CandidateRef); err != nil {
1037					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1038						Path:    meta.CandidateRef,
1039						Class:   "candidate_ref_prune",
1040						Message: err.Error(),
1041					})
1042					continue
1043				}
1044			}
1045			summary.PrunedCandidateRefs++
1046			class := "pruned_candidate_ref"
1047			if m.DryRun {
1048				class = "would_prune_candidate_ref"
1049			}
1050			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1051				Path:    meta.CandidateRef,
1052				Class:   class,
1053				Message: "landed candidate metadata durable in " + filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, entry.Name(), "result.json")),
1054			})
1055		}
1056	}
