1133	// pruneEvidenceDirs deletes .ddx/executions/<attempt-id>/ dirs whose mtime
1134	// is older than m.RetainDays. Dirs referenced by active run-states or lacking
1135	// a result.json are preserved. No-op when RetainDays == 0 (disabled).
1136	func (m *ExecutionCleanupManager) pruneEvidenceDirs(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
1137		if m.RetainDays == 0 {
1138			return
1139		}
1140		if ctx != nil && ctx.Err() != nil {
1141			return
1142		}
1143		cutoff := now.AddDate(0, 0, -m.RetainDays)
1144	
1145		activeAttempts := map[string]struct{}{}
1146		for _, rs := range runStates {
1147			if rs.AttemptID != "" {
1148				activeAttempts[rs.AttemptID] = struct{}{}
1149			}
1150		}
1151	
1152		root := executeBeadArtifactRoot(m.ProjectRoot)
1153		entries, err := os.ReadDir(root)
1154		if err != nil {
1155			if !errors.Is(err, os.ErrNotExist) {
1156				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1157					Path:    root,
1158					Class:   "evidence_dir_read",
1159					Message: err.Error(),
1160				})
1161			}
1162			return
1163		}
1164	
1165		for _, entry := range entries {
1166			if ctx != nil && ctx.Err() != nil {
1167				return
1168			}
1169			if !entry.IsDir() {
1170				continue
1171			}
1172			dirName := entry.Name()
1173			dirPath := filepath.Join(root, dirName)
1174			relPath := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, dirName))
1175	
1176			if _, ok := activeAttempts[dirName]; ok {
1177				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1178					Path:    relPath,
1179					Class:   "preserved_active_evidence_dir",
1180					Message: "active run-state reference",
1181				})
1182				continue
1183			}
1184	
1185			// Defensive: skip dirs with no result.json (may be in-flight).
1186			if _, statErr := os.Stat(filepath.Join(dirPath, "result.json")); statErr != nil {
1187				continue
1188			}
1189	
1190			info, infoErr := entry.Info()
1191			if infoErr != nil {
1192				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1193					Path:    dirPath,
1194					Class:   "evidence_dir_stat",
1195					Message: infoErr.Error(),
1196				})
1197				continue
1198			}
1199			if !info.ModTime().Before(cutoff) {
1200				continue
1201			}
1202	
1203			if !m.DryRun {
1204				m.removeEvidenceDir(ctx, dirPath, summary)
1205			}
1206			summary.RemovedEvidenceDirs++
1207			class := "removed_evidence_dir"
1208			if m.DryRun {
1209				class = "would_remove_evidence_dir"
1210			}
1211			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1212				Path:    relPath,
1213				Class:   class,
1214				Message: fmt.Sprintf("evidence dir older than %d days", m.RetainDays),
1215			})
1216		}
1217	}
1218	
1219	// removeEvidenceDir stages tracked files for deletion via git rm, then
1220	// removes any remaining files with os.RemoveAll.
1221	func (m *ExecutionCleanupManager) removeEvidenceDir(ctx context.Context, dirPath string, summary *ExecutionCleanupSummary) {
1222		if m.ProjectRoot == "" {
1223			_ = os.RemoveAll(dirPath)
1224			return
1225		}
1226		rel, err := filepath.Rel(m.ProjectRoot, dirPath)
1227		if err != nil || strings.HasPrefix(rel, "..") {
1228			_ = os.RemoveAll(dirPath)
1229			return
1230		}
1231		relSlash := filepath.ToSlash(rel)
1232	
1233		// Check for tracked files; if any, stage their deletion via git rm.
1234		lsOut, lsErr := internalgit.Command(ctx, m.ProjectRoot, "ls-files", relSlash).Output()
1235		if lsErr == nil && len(strings.TrimSpace(string(lsOut))) > 0 {
1236			rmOut, rmErr := internalgit.Command(ctx, m.ProjectRoot, "rm", "-rf", relSlash).CombinedOutput()
1237			if rmErr != nil {
1238				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1239					Path:    dirPath,
1240					Class:   "evidence_dir_git_rm",
1241					Message: fmt.Sprintf("git rm: %s: %v", strings.TrimSpace(string(rmOut)), rmErr),
1242				})
1243			}
1244		}
1245		// Remove remaining untracked files.
1246		_ = os.RemoveAll(dirPath)
