1249	// pruneAgentLogs deletes .ddx/agent-logs/agent-*.jsonl and svc-*.jsonl files
1250	// whose mtime is older than m.RetainDays. Files whose session_id matches an
1251	// active run-state are skipped. No-op when RetainDays == 0.
1252	func (m *ExecutionCleanupManager) pruneAgentLogs(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
1253		if m.RetainDays == 0 {
1254			return
1255		}
1256		if ctx != nil && ctx.Err() != nil {
1257			return
1258		}
1259		cutoff := now.AddDate(0, 0, -m.RetainDays)
1260	
1261		activeSessions := map[string]struct{}{}
1262		for _, rs := range runStates {
1263			if rs.SessionID != "" {
1264				activeSessions[rs.SessionID] = struct{}{}
1265			}
1266		}
1267	
1268		root := ddxroot.JoinProject(m.ProjectRoot, "agent-logs")
1269		entries, err := os.ReadDir(root)
1270		if err != nil {
1271			if !errors.Is(err, os.ErrNotExist) {
1272				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1273					Path:    root,
1274					Class:   "agent_log_read",
1275					Message: err.Error(),
1276				})
1277			}
1278			return
1279		}
1280	
1281		for _, entry := range entries {
1282			if ctx != nil && ctx.Err() != nil {
1283				return
1284			}
1285			if entry.IsDir() {
1286				continue
1287			}
1288			name := entry.Name()
1289			var sessionID string
1290			switch {
1291			case strings.HasPrefix(name, "agent-") && strings.HasSuffix(name, ".jsonl"):
1292				sessionID = strings.TrimSuffix(strings.TrimPrefix(name, "agent-"), ".jsonl")
1293			case strings.HasPrefix(name, "svc-") && strings.HasSuffix(name, ".jsonl"):
1294				sessionID = strings.TrimSuffix(strings.TrimPrefix(name, "svc-"), ".jsonl")
1295			default:
1296				continue
1297			}
1298			if _, ok := activeSessions[sessionID]; ok {
1299				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1300					Path:    filepath.ToSlash(filepath.Join(".ddx/agent-logs", name)),
1301					Class:   "preserved_active_agent_log",
1302					Message: "active run-state session reference",
1303				})
1304				continue
1305			}
1306			info, infoErr := entry.Info()
1307			if infoErr != nil {
1308				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1309					Path:    filepath.Join(root, name),
1310					Class:   "agent_log_stat",
1311					Message: infoErr.Error(),
1312				})
1313				continue
1314			}
1315			if !info.ModTime().Before(cutoff) {
1316				continue
1317			}
1318			path := filepath.Join(root, name)
1319			if !m.DryRun {
1320				if err := os.Remove(path); err != nil {
1321					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
1322						Path:    path,
1323						Class:   "agent_log_remove",
1324						Message: err.Error(),
1325					})
1326					continue
1327				}
1328			}
1329			summary.RemovedAgentLogs++
1330			class := "removed_agent_log"
1331			if m.DryRun {
1332				class = "would_remove_agent_log"
1333			}
1334			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1335				Path:    filepath.ToSlash(filepath.Join(".ddx/agent-logs", name)),
1336				Class:   class,
1337				Message: fmt.Sprintf("agent log older than %d days", m.RetainDays),
1338			})
1339		}
1340	}
