1446	func scanCompleteEvidenceDirs(projectRoot, rootRel string, primaryFile, secondaryFile string, summary *ExecutionCleanupSummary) int {
1447		root := projectStatePath(projectRoot, rootRel)
1448		entries, err := os.ReadDir(root)
1449		if err != nil {
1450			return 0
1451		}
1452		count := 0
1453		for _, entry := range entries {
1454			if !entry.IsDir() {
1455				continue
1456			}
1457			count++
1458			full := filepath.Join(root, entry.Name())
1459			complete := false
1460			if primaryFile != "" {
1461				if _, err := os.Stat(filepath.Join(full, primaryFile)); err == nil {
1462					complete = true
1463				}
1464			}
1465			if !complete && secondaryFile != "" {
1466				if _, err := os.Stat(filepath.Join(full, secondaryFile)); err == nil {
1467					complete = true
1468				}
1469			}
1470			if complete {
1471				summary.CompleteEvidenceDirs++
1472				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
1473					Path:    filepath.ToSlash(filepath.Join(rootRel, entry.Name())),
1474					Class:   "complete_evidence",
1475					Message: "complete evidence preserved",
1476				})
1477			}
1478		}
1479		return count
1480	}
