129	func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
130		if report.TempRoot == "" {
131			return nil
132		}
133		if ctx != nil {
134			if err := ctx.Err(); err != nil {
135				return err
136			}
137		}
138		entries, err := os.ReadDir(report.TempRoot)
139		if err != nil {
140			if os.IsNotExist(err) {
141				return nil
142			}
143			return err
144		}
145	
146		registered := map[string]struct{}{}
147		if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
148			for _, path := range paths {
149				registered[filepath.Clean(path)] = struct{}{}
150			}
151		}
152	
153		for _, entry := range entries {
154			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
155				continue
156			}
157			if ctx != nil {
158				if err := ctx.Err(); err != nil {
159					return err
160				}
161			}
162			info, err := entry.Info()
163			if err != nil {
164				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
165					Path:    filepath.Join(report.TempRoot, entry.Name()),
166					Class:   "worktree_stat",
167					Message: err.Error(),
168				})
169				continue
170			}
171			if now.Sub(info.ModTime()) < r.worktreeMaxAge {
172				continue
173			}
174	
175			path := filepath.Join(report.TempRoot, entry.Name())
176			meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
177			if metaErr == nil {
178				meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
179			} else {
180				meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
181			}
182			if worktreeStillLive(meta, runStates, now) {
183				continue
184			}
185	
186			report.StaleWorktrees++
187			if !apply {
188				continue
189			}
190	
191			if _, ok := registered[filepath.Clean(path)]; ok {
192				if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
193					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
194						Path:    path,
195						Class:   "registered_worktree_remove",
196						Message: err.Error(),
197					})
198					continue
199				}
200				report.RemovedRegisteredWorktrees++
201				continue
202			}
203	
204			if err := os.RemoveAll(path); err != nil {
205				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
206					Path:    path,
207					Class:   "unregistered_worktree_remove",
208					Message: err.Error(),
209				})
210				continue
211			}
212			report.RemovedUnregisteredTempDirs++
213		}
214	
215		return nil
216	}
217	
218	func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
219		root := workerstatus.LivenessDir(r.projectRoot)
220		entries, err := os.ReadDir(root)
221		if err != nil {
222			if os.IsNotExist(err) {
223				return nil
224			}
225			return err
226		}
227	
228		for _, entry := range entries {
229			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
230				continue
231			}
232			if ctx != nil {
233				if err := ctx.Err(); err != nil {
234					return err
235				}
236			}
237	
238			rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
239			if err != nil {
240				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
241					Path:    filepath.Join(root, entry.Name(), "status.json"),
242					Class:   "worker_dir_read",
243					Message: err.Error(),
244				})
245				continue
246			}
247			stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
248			if !stale {
249				continue
250			}
251	
252			report.StaleWorkerDirs++
253			if !apply {
254				continue
255			}
256	
257			dirPath := filepath.Join(root, entry.Name())
258			if err := os.RemoveAll(dirPath); err != nil {
259				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
260					Path:    dirPath,
261					Class:   "worker_dir_remove",
262					Message: err.Error(),
263				})
264				continue
265			}
266			report.RemovedWorkerDirs++
267		}
268	
269		return nil
270	}
271	
272	func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
273		policy := r.retentionPolicy
274		if policy.mode == executionRetentionDisabled {
275			return nil
276		}
277	
278		root := ddxroot.JoinProject(r.projectRoot, "executions")
279		entries, err := os.ReadDir(root)
280		if err != nil {
281			if os.IsNotExist(err) {
282				return nil
283			}
284			return err
285		}
286	
287		activeAttempts := map[string]struct{}{}
288		for _, rs := range runStates {
289			if rs.AttemptID != "" {
290				activeAttempts[rs.AttemptID] = struct{}{}
291			}
292		}
293		cutoff := now.AddDate(0, 0, -policy.days)
294	
295		for _, entry := range entries {
296			if !entry.IsDir() {
297				continue
298			}
299			if _, ok := activeAttempts[entry.Name()]; ok {
300				continue
301			}
302			if ctx != nil {
303				if err := ctx.Err(); err != nil {
304					return err
305				}
306			}
307	
308			dirPath := filepath.Join(root, entry.Name())
309			if !hasExecutionEvidenceMarker(dirPath) {
310				continue
311			}
312	
313			info, err := entry.Info()
314			if err != nil {
315				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
316					Path:    dirPath,
317					Class:   "execution_dir_stat",
318					Message: err.Error(),
319				})
320				continue
321			}
322			if !info.ModTime().Before(cutoff) {
323				continue
324			}
325	
326			report.StaleExecutionDirs++
327			if !apply {
328				continue
329			}
330	
331			switch policy.mode {
332			case executionRetentionArchive:
333				if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
334					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
335						Path:    dirPath,
336						Class:   "execution_dir_archive",
337						Message: err.Error(),
338					})
339					continue
340				}
341				report.ArchivedExecutionDirs++
342			case executionRetentionDelete:
343				if err := os.RemoveAll(dirPath); err != nil {
344					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
345						Path:    dirPath,
346						Class:   "execution_dir_remove",
347						Message: err.Error(),
348					})
349					continue
350				}
351				report.DeletedExecutionDirs++
352			}
353		}
354	
355		return nil
356	}
357	
358	func staleWorkerDir(rec workerstatus.LivenessRecord, now time.Time, maxAge time.Duration) (bool, string) {
359		if rec.PID > 0 && !processAlive(rec.PID) {
360			return true, fmt.Sprintf("worker pid %d is no longer live", rec.PID)
361		}
362		if !rec.LastActivityAt.IsZero() && now.Sub(rec.LastActivityAt) > maxAge {
363			return true, fmt.Sprintf("last activity older than %s", maxAge)
364		}
365		return false, ""
366	}
367	
368	func resolveExecutionRetentionPolicy(projectRoot string) executionRetentionPolicy {
369		if raw := strings.TrimSpace(os.Getenv(executionRetentionOverrideEnv)); raw != "" {
370			if days, err := strconv.Atoi(raw); err == nil && days >= 0 {
371				if days == 0 {
372					return executionRetentionPolicy{days: 0, mode: executionRetentionDelete}
373				}
374				return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
375			}
376		}
377	
378		cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
379		cfg, err := config.LoadFromFile(cfgPath)
380		if err != nil || cfg == nil || cfg.Executions == nil {
381			return executionRetentionPolicy{days: 90, mode: executionRetentionArchive}
382		}
383		days := cfg.Executions.ResolveRetainDays()
384		if days == 0 {
385			return executionRetentionPolicy{days: 0, mode: executionRetentionDisabled}
386		}
387		return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
388	}
389	
390	func hasExecutionEvidenceMarker(dirPath string) bool {
391		for _, name := range []string{"result.json", "manifest.json"} {
392			if _, err := os.Stat(filepath.Join(dirPath, name)); err == nil {
393				return true
394			}
395		}
396		return false
397	}
398	
399	func archiveExecutionDir(projectRoot, dirPath, attemptID string, modTime time.Time) error {
400		year, month := executionArchiveBucket(attemptID, modTime.UTC())
401		dstRoot := filepath.Join(projectRoot, filepath.FromSlash(executionRetentionArchiveRoot), year, month)
402		if err := os.MkdirAll(dstRoot, 0o755); err != nil {
403			return fmt.Errorf("mkdir archive dir: %w", err)
404		}
405		dstPath := filepath.Join(dstRoot, attemptID)
406		if _, err := os.Stat(dstPath); err == nil {
407			return fmt.Errorf("archive destination already exists: %s", dstPath)
408		} else if !errors.Is(err, os.ErrNotExist) {
409			return err
410		}
411		return os.Rename(dirPath, dstPath)
412	}
413	
414	func executionArchiveBucket(attemptID string, modTime time.Time) (string, string) {
415		ts := attemptID
416		if idx := strings.IndexByte(ts, '-'); idx >= 0 {
417			ts = ts[:idx]
418		}
419		if parsed, err := time.ParseInLocation(executionRetentionTimestampLayout, ts, time.UTC); err == nil {
420			return parsed.Format("2006"), parsed.Format("01")
421		}
422		if modTime.IsZero() {
423			modTime = time.Now().UTC()
424		}
425		return modTime.Format("2006"), modTime.Format("01")
426	}
