1	//go:build linux
2	
3	package workerstatus
4	
5	import (
6		"bytes"
7		"context"
8		"fmt"
9		"os"
10		"path/filepath"
11		"strconv"
12		"strings"
13		"time"
14	
15		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
16	)
17	
18	// newSystemScanner returns a /proc-based scanner.
19	func newSystemScanner() Scanner {
20		return &procScanner{now: time.Now}
21	}
22	
23	// procScanner enumerates live `ddx work` and `ddx try` processes by reading
24	// /proc on Linux. Each candidate's command line, cwd, and start time are
25	// pulled directly from the kernel, so the scan does not depend on any DDx
26	// server state.
27	type procScanner struct {
28		now func() time.Time
29	}
30	
31	func (s *procScanner) Scan(ctx context.Context) ([]LiveWorker, error) {
32		entries, err := os.ReadDir("/proc")
33		if err != nil {
34			return nil, fmt.Errorf("read /proc: %w", err)
35		}
36	
37		workers := make([]LiveWorker, 0)
38		bootTime := readBootTime("/proc/stat")
39		for _, e := range entries {
40			if ctx != nil && ctx.Err() != nil {
41				return nil, ctx.Err()
42			}
43			if !e.IsDir() {
44				continue
45			}
46			pid, err := strconv.Atoi(e.Name())
47			if err != nil || pid <= 0 {
48				continue
49			}
50			w, ok := s.inspect(pid, bootTime)
51			if !ok {
52				continue
53			}
54			workers = append(workers, w)
55		}
56		return workers, nil
57	}
58	
59	func (s *procScanner) inspect(pid int, bootTime time.Time) (LiveWorker, bool) {
60		base := filepath.Join("/proc", strconv.Itoa(pid))
61		cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
62		if err != nil {
63			return LiveWorker{}, false
64		}
65		cmdline := decodeCmdline(cmdlineRaw)
66		if !looksLikeDDxWorker(cmdline) {
67			return LiveWorker{}, false
68		}
69	
70		cwd, _ := os.Readlink(filepath.Join(base, "cwd"))
71	
72		projectRoot := resolveWorkerProjectRoot(cmdline, cwd)
73		beadID, worktree := InferBead(cmdline, cwd)
74	
75		started := time.Time{}
76		if !bootTime.IsZero() {
77			if startClk, ok := readStartTimeClockTicks(filepath.Join(base, "stat")); ok {
78				ticks := clockTicksPerSecond()
79				seconds := float64(startClk) / ticks
80				started = bootTime.Add(time.Duration(seconds * float64(time.Second)))
81			}
82		}
83		now := s.now().UTC()
84		if started.IsZero() {
85			started = now
86		}
87		age := now.Sub(started)
88		if age < 0 {
89			age = 0
90		}
91	
92		return LiveWorker{
93			PID:               pid,
94			Command:           cmdline,
95			StartedAt:         started.UTC(),
96			AgeSeconds:        age.Seconds(),
97			Age:               FormatAge(age),
98			ProjectRoot:       projectRoot,
99			BeadID:            beadID,
100			ExecutionWorktree: worktree,
101			Cwd:               cwd,
102		}, true
103	}
104	
105	// decodeCmdline converts /proc/<pid>/cmdline's NUL-separated args into a
106	// space-separated string suitable for display and substring matching.
107	func decodeCmdline(raw []byte) string {
108		if len(raw) == 0 {
109			return ""
110		}
111		if raw[len(raw)-1] == 0 {
112			raw = raw[:len(raw)-1]
113		}
114		parts := bytes.Split(raw, []byte{0})
115		out := make([]string, 0, len(parts))
116		for _, p := range parts {
117			if len(p) == 0 {
118				continue
119			}
120			out = append(out, string(p))
121		}
122		return strings.Join(out, " ")
123	}
124	
125	// looksLikeDDxWorker reports whether the argv resembles a `ddx work` or
126	// `ddx try` invocation. We match against argv[0]'s basename so a binary
127	// installed at any path (or via `go run ./cli ...`) is still detected.
128	func looksLikeDDxWorker(cmdline string) bool {
129		if cmdline == "" {
130			return false
131		}
132		parts := strings.Fields(cmdline)
133		if len(parts) < 2 {
134			return false
135		}
136		bin := filepath.Base(parts[0])
137		if bin != "ddx" {
138			// Allow `go run ... ddx work` style invocations where the binary
139			// path ends in `cmd` or similar but the args still start with the
140			// ddx subcommand. We only consider real ddx binaries here.
141			return false
142		}
143		sub := parts[1]
144		if sub == "try" {
145			return true
146		}
147		if sub != "work" {
148			return false
149		}
150		if len(parts) >= 3 && isWorkHelperSubcommand(parts[2]) {
151			return false
152		}
153		return true
154	}
155	
156	func isWorkHelperSubcommand(arg string) bool {
157		switch arg {
158		case "analyze", "clear-cooldowns", "focus", "metrics", "plan", "status":
159			return true
160		default:
161			return false
162		}
163	}
164	
165	// resolveWorkerProjectRoot derives the project root the worker is operating
166	// on. The order of preference matches how `ddx work` itself resolves --project
167	// (CLI flag → DDX_PROJECT_ROOT env → cwd's git root). When the cwd points at
168	// an isolated execute-bead worktree (a sibling of the real checkout), we
169	// fall back to the surrounding git root rather than the worktree path.
170	func resolveWorkerProjectRoot(cmdline, cwd string) string {
171		if flagVal := parseFlagValue(cmdline, "--project"); flagVal != "" {
172			return canonicalPath(flagVal)
173		}
174		if cwd == "" {
175			return ""
176		}
177		// If cwd is inside an isolated execute-bead worktree the git root will
178		// be the worktree itself; that is a per-attempt artefact, not the
179		// originating project. Worktree paths conventionally live under either
180		// `<project>/.ddx/.execute-bead-wt-*` or under DDX_EXEC_WT_DIR. Caller
181		// resolution here only needs to keep workers consistent: we always
182		// derive ProjectRoot from cwd's git root via the same helper the worker
183		// itself would use.
184		root := gitpkg.FindProjectRoot(cwd)
185		return canonicalPath(root)
186	}
187	
188	// parseFlagValue returns the argument value for a `--flag <value>` or
189	// `--flag=<value>` form embedded in a space-separated command line. The
190	// match is anchored at word boundaries so `--projectile` does not satisfy
191	// `--project`.
192	func parseFlagValue(cmdline, flag string) string {
193		parts := strings.Fields(cmdline)
194		for i, p := range parts {
195			if p == flag && i+1 < len(parts) {
196				return parts[i+1]
197			}
198			if strings.HasPrefix(p, flag+"=") {
199				return strings.TrimPrefix(p, flag+"=")
200			}
201		}
202		return ""
203	}
204	
205	func readBootTime(statPath string) time.Time {
206		data, err := os.ReadFile(statPath)
207		if err != nil {
208			return time.Time{}
209		}
210		for _, line := range strings.Split(string(data), "\n") {
211			if !strings.HasPrefix(line, "btime ") {
212				continue
213			}
214			fields := strings.Fields(line)
215			if len(fields) < 2 {
216				continue
217			}
218			sec, err := strconv.ParseInt(fields[1], 10, 64)
219			if err != nil {
220				return time.Time{}
221			}
222			return time.Unix(sec, 0)
223		}
224		return time.Time{}
225	}
226	
227	func readStartTimeClockTicks(statPath string) (int64, bool) {
228		data, err := os.ReadFile(statPath)
229		if err != nil {
230			return 0, false
231		}
232		// The 22nd field of /proc/<pid>/stat is starttime (clock ticks since
233		// boot). The 2nd field (comm) is wrapped in parentheses and may itself
234		// contain spaces, so we scan from the last ')' to skip it cleanly.
235		close := strings.LastIndex(string(data), ")")
236		if close < 0 {
237			return 0, false
238		}
239		tail := strings.Fields(string(data)[close+1:])
240		// After the comm field, the index of starttime is 22 - 2 = 20 (zero-
241		// based) in the tail slice (because state is index 0 in the tail).
242		const starttimeIndex = 22 - 3
243		if starttimeIndex >= len(tail) {
244			return 0, false
245		}
246		v, err := strconv.ParseInt(tail[starttimeIndex], 10, 64)
247		if err != nil {
248			return 0, false
249		}
250		return v, true
251	}
252	
253	func clockTicksPerSecond() float64 {
254		// Linux exposes CLK_TCK as a sysconf value; the kernel default on
255		// every platform DDx supports is 100. Using the constant keeps us
256		// free of cgo without changing the calculated age in practice.
257		return 100.0
258	}
259

1	// Package workerstatus reports on live "ddx work" / "ddx try" processes,
2	// scoped to a specific project root by default.
3	//
4	// Operators and agents asking "is the worker still working beads?" must be
5	// able to answer the question for one project at a time. A global process
6	// scan ("ps aux | grep ddx work") returns workers from every checkout on the
7	// machine and produces a misleading "yes, working" signal when the worker
8	// belongs to a different repository. This package filters live workers by
9	// the resolved project root so the answer always matches the question.
10	package workerstatus
11	
12	import (
13		"context"
14		"path/filepath"
15		"regexp"
16		"strings"
17		"time"
18	)
19	
20	// LiveWorker describes one running ddx worker process.
21	type LiveWorker struct {
22		PID               int       `json:"pid"`
23		Command           string    `json:"command"`
24		StartedAt         time.Time `json:"started_at"`
25		AgeSeconds        float64   `json:"age_seconds"`
26		Age               string    `json:"age"`
27		ProjectRoot       string    `json:"project_root"`
28		BeadID            string    `json:"bead_id,omitempty"`
29		AttemptID         string    `json:"attempt_id,omitempty"`
30		Phase             string    `json:"phase,omitempty"`
31		Message           string    `json:"message,omitempty"`
32		ChildPID          int       `json:"child_pid,omitempty"`
33		LastActivityAt    time.Time `json:"last_activity_at,omitempty"`
34		ExecutionWorktree string    `json:"execution_worktree,omitempty"`
35		Cwd               string    `json:"cwd,omitempty"`
36	}
37	
38	// Scanner discovers live ddx worker processes on the host.
39	type Scanner interface {
40		Scan(ctx context.Context) ([]LiveWorker, error)
41	}
42	
43	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
44	// On other platforms it returns an empty list; the caller's tests and the
45	// --all-projects escape hatch remain meaningful regardless.
46	func New() Scanner {
47		return newSystemScanner()
48	}
49	
50	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
51	// total) embedded in argv strings or worktree paths.
52	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
53	
54	// executionWorktreePattern matches the conventional execute-bead worktree
55	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
56	// in a path. The directory name is enough to identify the worktree even when
57	// the surrounding path is unconventional.
58	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
59	
60	// InferBead extracts a bead ID and execution worktree path from the worker's
61	// command line and current working directory. It returns the longest worktree
62	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
63	// the inline worker has chdir'd into the isolated worktree), and the first
64	// bead ID matched in either the command line or the worktree path.
65	//
66	// Either return value may be empty when no signal is present, which is the
67	// expected case for a long-running `ddx work` drain that has not yet started
68	// a specific bead.
69	func InferBead(cmdline, cwd string) (beadID, worktree string) {
70		worktree = extractWorktreePath(cwd)
71		if worktree == "" {
72			worktree = extractWorktreePath(cmdline)
73		}
74	
75		if m := beadIDPattern.FindString(worktree); m != "" {
76			beadID = m
77		}
78		if beadID == "" {
79			if m := beadIDPattern.FindString(cmdline); m != "" {
80				beadID = m
81			}
82		}
83		if beadID == "" {
84			if m := beadIDPattern.FindString(cwd); m != "" {
85				beadID = m
86			}
87		}
88		return beadID, worktree
89	}
