91	func extractWorktreePath(s string) string {
92		if s == "" {
93			return ""
94		}
95		if !strings.Contains(s, ".execute-bead-wt-") {
96			return ""
97		}
98		matches := executionWorktreePattern.FindStringIndex(s)
99		if matches == nil {
100			return ""
101		}
102		start := matches[0]
103		end := matches[1]
104		for start > 0 {
105			r := s[start-1]
106			if r == ' ' || r == '\x00' || r == '\t' {
107				break
108			}
109			start--
110		}
111		for end < len(s) {
112			r := s[end]
113			if r == ' ' || r == '\x00' || r == '\t' {
114				break
115			}
116			end++
117		}
118		return s[start:end]
119	}
