161	// FormatAge renders a duration as a short human-readable string mirroring
162	// the conventions used by the server-backed worker list (`5s`, `12m`,
163	// `1h30m`). It is intended for terminal output; JSON output uses
164	// AgeSeconds as the numeric source of truth.
165	func FormatAge(d time.Duration) string {
166		if d < time.Minute {
167			if d < 0 {
168				d = 0
169			}
170			return roundedSeconds(d)
171		}
172		if d < time.Hour {
173			return roundedMinutes(d)
174		}
175		hours := int(d.Hours())
176		mins := int(d.Minutes()) % 60
177		if mins == 0 {
178			return durationHours(hours)
179		}
180		return durationHoursMinutes(hours, mins)
181	}
182	
183	func roundedSeconds(d time.Duration) string {
184		secs := int(d.Seconds())
185		return durationSeconds(secs)
186	}
187	
188	func roundedMinutes(d time.Duration) string {
189		mins := int(d.Minutes())
190		return durationMinutes(mins)
191	}
192	
193	func durationSeconds(n int) string { return formatUnit(n, "s") }
194	func durationMinutes(n int) string { return formatUnit(n, "m") }
195	func durationHours(n int) string   { return formatUnit(n, "h") }
196	func durationHoursMinutes(h, m int) string {
197		return formatUnit(h, "h") + formatUnit(m, "m")
198	}
199	
200	func formatUnit(n int, unit string) string {
201		if n < 0 {
202			n = 0
203		}
204		return itoa(n) + unit
205	}
206	
207	func itoa(n int) string {
208		if n == 0 {
209			return "0"
210		}
211		neg := n < 0
212		if neg {
213			n = -n
214		}
215		var digits [20]byte
216		i := len(digits)
217		for n > 0 {
218			i--
219			digits[i] = byte('0' + n%10)
220			n /= 10
221		}
222		out := string(digits[i:])
223		if neg {
224			return "-" + out
225		}
226		return out
227	}
