package agent

import (
	"context"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"
)

// AttemptDescendantProcess describes a process found under a DDx execution
// worktree during a cleanup scan.
type AttemptDescendantProcess struct {
	PID         int    `json:"pid"`
	PGID        int    `json:"pgid,omitempty"`
	Command     string `json:"command"`
	Cwd         string `json:"cwd"`
	Worktree    string `json:"worktree"`
	BeadID      string `json:"bead_id,omitempty"`
	AttemptID   string `json:"attempt_id,omitempty"`
	StaleReason string `json:"stale_reason"`
	WouldKill   bool   `json:"would_kill"`
}

// AttemptDescendantScanner enumerates processes whose cwd sits inside a DDx
// execution temp root.
type AttemptDescendantScanner interface {
	ScanUnder(ctx context.Context, execRoot string) ([]AttemptDescendantProcess, error)
}

// AttemptDescendantKiller terminates the process group of the given PID.
type AttemptDescendantKiller interface {
	KillGroup(pid int) error
}

// NewAttemptDescendantScanner returns the platform-appropriate scanner.
// On Linux it reads /proc; on other platforms it returns an empty-list no-op.
func NewAttemptDescendantScanner() AttemptDescendantScanner {
	return newAttemptDescendantScanner()
}

// NewAttemptDescendantKiller returns the platform-appropriate process-group killer.
// On Linux it sends SIGKILL to the process group; on other platforms it is a no-op.
func NewAttemptDescendantKiller() AttemptDescendantKiller {
	return newAttemptDescendantKiller()
}

// extractWorktreeFromCwd returns the DDx attempt worktree directory that
// contains cwd, or "" when cwd is not under a DDx attempt dir in execRoot.
func extractWorktreeFromCwd(cwd, execRoot string) string {
	if cwd == "" || execRoot == "" {
		return ""
	}
	cleanCwd := filepath.Clean(cwd)
	cleanRoot := filepath.Clean(execRoot)
	sep := string(filepath.Separator)
	if !strings.HasPrefix(cleanCwd, cleanRoot+sep) {
		return ""
	}
	rel := cleanCwd[len(cleanRoot)+len(sep):]
	parts := strings.SplitN(rel, sep, 2)
	if len(parts) == 0 || parts[0] == "" {
		return ""
	}
	first := parts[0]
	if !hasAnyPrefix(first, executionAttemptDirPrefixes()) {
		return ""
	}
	return filepath.Join(cleanRoot, first)
}

// ReapStaleAttemptDescendants reports and optionally kills processes under
// execRoot whose worktrees are no longer live. It is used by both the cleanup
// command and work startup to conservatively reap orphaned attempt-descendant
// processes. Non-fatal scan errors are surfaced as warnings in the summary.
func ReapStaleAttemptDescendants(
	ctx context.Context,
	execRoot string,
	runStates []RunState,
	registered map[string]struct{},
	probe ExecutionCleanupLivenessProbe,
	scanner AttemptDescendantScanner,
	killer AttemptDescendantKiller,
	dryRun bool,
	now time.Time,
	summary *ExecutionCleanupSummary,
) error {
	return reapStaleAttemptDescendants(ctx, execRoot, runStates, registered, probe, scanner, killer, dryRun, now, summary)
}

func reapStaleAttemptDescendants(
	ctx context.Context,
	execRoot string,
	runStates []RunState,
	registered map[string]struct{},
	probe ExecutionCleanupLivenessProbe,
	scanner AttemptDescendantScanner,
	killer AttemptDescendantKiller,
	dryRun bool,
	now time.Time,
	summary *ExecutionCleanupSummary,
) error {
	if scanner == nil || execRoot == "" {
		return nil
	}
	if ctx != nil && ctx.Err() != nil {
		return ctx.Err()
	}
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}
	if registered == nil {
		registered = map[string]struct{}{}
	}

	procs, err := scanner.ScanUnder(ctx, execRoot)
	if err != nil {
		summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
			Class:   "process_scan",
			Message: err.Error(),
		})
		return nil // non-fatal: continue with file cleanup
	}

	for _, proc := range procs {
		if ctx != nil && ctx.Err() != nil {
			return ctx.Err()
		}
		if proc.Worktree == "" {
			continue
		}
		// Never touch a worktree that is still registered with git.
		if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "preserved_process_registered_worktree",
				Message: fmt.Sprintf("pid %d preserved: worktree is registered", proc.PID),
			})
			continue
		}

		meta, metaErr := ReadExecutionCleanupMetadata(proc.Worktree)
		if metaErr != nil {
			if !errors.Is(metaErr, os.ErrNotExist) {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    proc.Worktree,
					Class:   "process_metadata_read",
					Message: metaErr.Error(),
				})
				continue
			}
			meta = ExecutionCleanupMetadata{WorktreePath: proc.Worktree}
		}
		if meta.BeadID == "" {
			meta.BeadID = proc.BeadID
		}
		if meta.AttemptID == "" {
			meta.AttemptID = proc.AttemptID
		}

		matchedRunState := matchingRunStateForMeta(runStates, meta)
		live, reason := probe.IsLive(meta, matchedRunState, now)
		if live {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "preserved_process_live_worktree",
				Message: fmt.Sprintf("pid %d preserved: %s", proc.PID, reason),
			})
			continue
		}

		proc.StaleReason = reason
		proc.WouldKill = true
		summary.StaleAttemptProcesses++
		summary.ProcessFindings = append(summary.ProcessFindings, proc)

		if dryRun {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "would_reap_attempt_descendant",
				Message: fmt.Sprintf("pid %d would be reaped: %s", proc.PID, reason),
			})
			continue
		}

		if killer == nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    proc.Worktree,
				Class:   "process_no_killer",
				Message: fmt.Sprintf("pid %d: no killer available on this platform", proc.PID),
			})
			continue
		}
		if killErr := killer.KillGroup(proc.PID); killErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    proc.Worktree,
				Class:   "process_kill",
				Message: fmt.Sprintf("failed to kill group %d: %v", proc.PID, killErr),
			})
		} else {
			summary.ReapedAttemptProcesses++
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "reaped_attempt_descendant",
				Message: fmt.Sprintf("pid %d reaped: %s", proc.PID, reason),
			})
		}
	}
	return nil
}

//go:build linux

package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

type procAttemptDescendantScanner struct{}

func newAttemptDescendantScanner() AttemptDescendantScanner {
	return procAttemptDescendantScanner{}
}

type pgidKiller struct{}

func (pgidKiller) KillGroup(pid int) error {
	return killProcessGroup(pid)
}

func newAttemptDescendantKiller() AttemptDescendantKiller {
	return pgidKiller{}
}

func (procAttemptDescendantScanner) ScanUnder(ctx context.Context, execRoot string) ([]AttemptDescendantProcess, error) {
	if execRoot == "" {
		return nil, nil
	}
	entries, err := os.ReadDir("/proc")
	if err != nil {
		return nil, fmt.Errorf("read /proc: %w", err)
	}
	var out []AttemptDescendantProcess
	for _, entry := range entries {
		if ctx != nil && ctx.Err() != nil {
			return nil, ctx.Err()
		}
		if !entry.IsDir() {
			continue
		}
		pid, err := strconv.Atoi(entry.Name())
		if err != nil || pid <= 0 {
			continue
		}
		proc, ok := inspectAttemptDescendantProcess(pid, execRoot)
		if !ok {
			continue
		}
		out = append(out, proc)
	}
	return out, nil
}

func inspectAttemptDescendantProcess(pid int, execRoot string) (AttemptDescendantProcess, bool) {
	base := filepath.Join("/proc", strconv.Itoa(pid))
	cwd, err := os.Readlink(filepath.Join(base, "cwd"))
	if err != nil {
		return AttemptDescendantProcess{}, false
	}
	worktree := extractWorktreeFromCwd(cwd, execRoot)
	if worktree == "" {
		return AttemptDescendantProcess{}, false
	}
	cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
	if err != nil {
		return AttemptDescendantProcess{}, false
	}
	cmdline := decodeOrphanHarnessCmdline(cmdlineRaw)
	pgid, _ := readAttemptDescendantPGID(filepath.Join(base, "stat"))

	beadID, _ := workerstatus.InferBead(cmdline, cwd)
	attemptID := extractAttemptIDFromWorktree(worktree)

	cmd := cmdline
	if len(cmd) > 120 {
		cmd = cmd[:120] + "..."
	}

	return AttemptDescendantProcess{
		PID:       pid,
		PGID:      pgid,
		Command:   cmd,
		Cwd:       cwd,
		Worktree:  worktree,
		BeadID:    beadID,
		AttemptID: attemptID,
	}, true
}

// readAttemptDescendantPGID reads the process group ID from /proc/<pid>/stat.
// After the closing ')' of the process name: state(0), ppid(1), pgrp(2).
func readAttemptDescendantPGID(statPath string) (int, bool) {
	data, err := os.ReadFile(statPath)
	if err != nil {
		return 0, false
	}
	close := strings.LastIndex(string(data), ")")
	if close < 0 {
		return 0, false
	}
	tail := strings.Fields(string(data[close+1:]))
	if len(tail) < 3 {
		return 0, false
	}
	pgid, err := strconv.Atoi(tail[2])
	if err != nil {
		return 0, false
	}
	return pgid, true
}

// extractAttemptIDFromWorktree parses the attemptID from a DDx worktree name.
// Format: <prefix><beadID>-<attemptID> e.g. .execute-bead-wt-ddx-abcd1234-20260611T000000-deadbeef
func extractAttemptIDFromWorktree(worktree string) string {
	name := filepath.Base(worktree)
	for _, prefix := range executionAttemptDirPrefixes() {
		if !strings.HasPrefix(name, prefix) {
			continue
		}
		rest := name[len(prefix):]
		// rest = "ddx-<8hex>-<attemptID>"
		if !strings.HasPrefix(rest, "ddx-") {
			break
		}
		rest = rest[4:] // skip "ddx-"
		// rest = "<8hex>-<attemptID>"
		idx := strings.Index(rest, "-")
		if idx >= 0 {
			return rest[idx+1:]
		}
		break
	}
	return ""
}

