func (r *startupHousekeepingRunner) scanAttemptDescendants(
	ctx context.Context,
	runStates []agent.RunState,
	apply bool,
	report *startupHousekeepingReport,
) error {
	if r == nil || r.processScanner == nil || r.tempRoot == "" {
		return nil
	}
	registered := map[string]struct{}{}
	if paths, err := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); err == nil {
		for _, p := range paths {
			registered[filepath.Clean(p)] = struct{}{}
		}
	}
	var summary agent.ExecutionCleanupSummary
	summary.ProjectRoot = r.projectRoot
	summary.TempRoot = r.tempRoot

	var killer agent.AttemptDescendantKiller
	if apply {
		killer = r.processKiller
	}
	now := time.Now().UTC()
	if r.now != nil {
		now = r.now()
	}
	if err := agent.ReapStaleAttemptDescendants(
		ctx, r.tempRoot, runStates, registered,
		nil, // default liveness probe
		r.processScanner, killer,
		!apply, now,
		&summary,
	); err != nil {
		return err
	}
	report.StaleAttemptProcesses += summary.StaleAttemptProcesses
	report.ReapedAttemptProcesses += summary.ReapedAttemptProcesses
	report.Warnings = append(report.Warnings, summary.Warnings...)
	report.Observations = append(report.Observations, summary.Observations...)
	return nil
}

