package agent

import (
	"context"
	"os"
	"path/filepath"
	"sync"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// fakeAttemptDescendantScanner is an injectable scanner for tests.
type fakeAttemptDescendantScanner struct {
	mu    sync.Mutex
	procs []AttemptDescendantProcess
	err   error
}

func (f *fakeAttemptDescendantScanner) ScanUnder(_ context.Context, _ string) ([]AttemptDescendantProcess, error) {
	f.mu.Lock()
	defer f.mu.Unlock()
	if f.err != nil {
		return nil, f.err
	}
	return append([]AttemptDescendantProcess(nil), f.procs...), nil
}

// fakeAttemptDescendantKiller records which PIDs were killed.
type fakeAttemptDescendantKiller struct {
	mu      sync.Mutex
	killed  []int
	killErr error
}

func (f *fakeAttemptDescendantKiller) KillGroup(pid int) error {
	f.mu.Lock()
	defer f.mu.Unlock()
	if f.killErr != nil {
		return f.killErr
	}
	f.killed = append(f.killed, pid)
	return nil
}

func setupAttemptDescendantReaperProject(t *testing.T) (string, string) {
	t.Helper()
	projectRoot := t.TempDir()
	require.NoError(t, os.MkdirAll(ddxroot.JoinProject(projectRoot), 0o755))
	tempRoot := filepath.Join(t.TempDir(), "exec-wt")
	require.NoError(t, os.MkdirAll(tempRoot, 0o755))
	return projectRoot, tempRoot
}

func makeStaleWorktree(t *testing.T, tempRoot, beadID, attemptID, projectRoot string) string {
	t.Helper()
	wt := filepath.Join(tempRoot, ExecuteBeadWtPrefix+beadID+"-"+attemptID)
	require.NoError(t, os.MkdirAll(wt, 0o755))
	require.NoError(t, WriteExecutionCleanupMetadata(wt, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       beadID,
		AttemptID:    attemptID,
		WorktreePath: wt,
	}))
	return wt
}

// TestExecutionCleanupManager_DryRunReportsStaleAttemptDescendantProcesses
// proves that dry-run reports a stale process (with pid, command, worktree,
// stale reason, would_kill=true) but does not invoke the killer (AC1).
func TestExecutionCleanupManager_DryRunReportsStaleAttemptDescendantProcesses(t *testing.T) {
	projectRoot, tempRoot := setupAttemptDescendantReaperProject(t)

	beadID := "ddx-deadbeef"
	attemptID := "20260611T000000-deadbeef"
	worktree := makeStaleWorktree(t, tempRoot, beadID, attemptID, projectRoot)

	fakeScanner := &fakeAttemptDescendantScanner{
		procs: []AttemptDescendantProcess{
			{
				PID:       9999,
				PGID:      9999,
				Command:   "sh -c sleep 30",
				Cwd:       worktree,
				Worktree:  worktree,
				BeadID:    beadID,
				AttemptID: attemptID,
			},
		},
	}
	fakeKiller := &fakeAttemptDescendantKiller{}

	mgr := NewExecutionCleanupManager(projectRoot, nil)
	mgr.TempRoot = tempRoot
	mgr.DryRun = true
	mgr.ProcessScanner = fakeScanner
	mgr.ProcessKiller = fakeKiller

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.Equal(t, int64(1), summary.StaleAttemptProcesses, "stale process count")
	assert.Equal(t, int64(0), summary.ReapedAttemptProcesses, "dry-run must not reap")
	require.Len(t, summary.ProcessFindings, 1)
	finding := summary.ProcessFindings[0]
	assert.Equal(t, 9999, finding.PID)
	assert.Equal(t, worktree, finding.Worktree)
	assert.NotEmpty(t, finding.StaleReason, "stale reason must be populated")
	assert.True(t, finding.WouldKill)

	fakeKiller.mu.Lock()
	assert.Empty(t, fakeKiller.killed, "dry-run must not call killer")
	fakeKiller.mu.Unlock()

	found := false
	for _, obs := range summary.Observations {
		if obs.Class == "would_reap_attempt_descendant" {
			found = true
			break
		}
	}
	assert.True(t, found, "expected would_reap_attempt_descendant observation in dry-run")
}

// TestExecutionCleanupManager_ApplyReapsOnlyStaleAttemptProcessGroups
// proves that --apply kills stale DDx-owned process groups while preserving
// live run-state processes and active registered worktree processes (AC2).
func TestExecutionCleanupManager_ApplyReapsOnlyStaleAttemptProcessGroups(t *testing.T) {
	projectRoot, tempRoot := setupAttemptDescendantReaperProject(t)

	// Stale worktree: no live run-state, no liveness.
	staleWT := makeStaleWorktree(t, tempRoot, "ddx-stale1111", "20260611T000000-aaaaaaaa", projectRoot)

	// Live worktree: liveness PID is the current process (alive).
	liveWT := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-live22222-20260611T000001-bbbbbbbb")
	require.NoError(t, os.MkdirAll(liveWT, 0o755))
	require.NoError(t, WriteExecutionCleanupMetadata(liveWT, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       "ddx-live22222",
		AttemptID:    "20260611T000001-bbbbbbbb",
		WorktreePath: liveWT,
		Liveness: &ExecutionCleanupLiveness{
			PID:         os.Getpid(),
			RefreshedAt: time.Now(),
			ExpiresAt:   time.Now().Add(time.Hour),
		},
	}))

	// Registered worktree: registered → preserved regardless of liveness.
	registeredWT := makeStaleWorktree(t, tempRoot, "ddx-reg333333", "20260611T000002-cccccccc", projectRoot)

	fakeScanner := &fakeAttemptDescendantScanner{
		procs: []AttemptDescendantProcess{
			{PID: 1001, PGID: 1001, Command: "sh stale", Cwd: staleWT, Worktree: staleWT, BeadID: "ddx-stale1111"},
			{PID: 1002, PGID: 1002, Command: "sh live", Cwd: liveWT, Worktree: liveWT, BeadID: "ddx-live22222"},
			{PID: 1003, PGID: 1003, Command: "sh registered", Cwd: registeredWT, Worktree: registeredWT, BeadID: "ddx-reg333333"},
		},
	}
	fakeKiller := &fakeAttemptDescendantKiller{}

	// Register the registered worktree so it is preserved.
	fakeGitOps := &executionCleanupTestGitOps{worktrees: []string{registeredWT}}

	mgr := NewExecutionCleanupManager(projectRoot, fakeGitOps)
	mgr.TempRoot = tempRoot
	mgr.DryRun = false
	mgr.ProcessScanner = fakeScanner
	mgr.ProcessKiller = fakeKiller

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	// Only stale process killed.
	assert.Equal(t, int64(1), summary.StaleAttemptProcesses)
	assert.Equal(t, int64(1), summary.ReapedAttemptProcesses)
	require.Len(t, summary.ProcessFindings, 1)
	assert.Equal(t, 1001, summary.ProcessFindings[0].PID)

	fakeKiller.mu.Lock()
	assert.Equal(t, []int{1001}, fakeKiller.killed, "only stale process group killed")
	fakeKiller.mu.Unlock()

	// Live and registered processes emitted as preserved observations.
	var preservedClasses []string
	for _, obs := range summary.Observations {
		if obs.Class == "preserved_process_live_worktree" || obs.Class == "preserved_process_registered_worktree" {
			preservedClasses = append(preservedClasses, obs.Class)
		}
	}
	assert.Contains(t, preservedClasses, "preserved_process_live_worktree")
	assert.Contains(t, preservedClasses, "preserved_process_registered_worktree")
}

// TestExecutionCleanupManager_NonHarnessDescendantDetectedByCwd proves that
// a non-harness descendant command (sh, cargo, or a test server) whose cwd is
// under a stale execution worktree is detected by DDx ownership/cwd/liveness
// evidence — not by command-name matching (AC5 regression).
func TestExecutionCleanupManager_NonHarnessDescendantDetectedByCwd(t *testing.T) {
	projectRoot, tempRoot := setupAttemptDescendantReaperProject(t)
	staleWT := makeStaleWorktree(t, tempRoot, "ddx-cargo9999", "20260611T010000-ffffffff", projectRoot)

	// Non-harness commands: shell, cargo, a generic server. All under the stale worktree.
	fakeScanner := &fakeAttemptDescendantScanner{
		procs: []AttemptDescendantProcess{
			{PID: 2001, PGID: 2001, Command: "sh -c cargo test --workspace", Cwd: staleWT, Worktree: staleWT},
			{PID: 2002, PGID: 2002, Command: "cargo test my_feature", Cwd: filepath.Join(staleWT, "target"), Worktree: staleWT},
			{PID: 2003, PGID: 2003, Command: "./test-server --port 8088", Cwd: staleWT, Worktree: staleWT},
		},
	}
	fakeKiller := &fakeAttemptDescendantKiller{}

	mgr := NewExecutionCleanupManager(projectRoot, nil)
	mgr.TempRoot = tempRoot
	mgr.DryRun = true
	mgr.ProcessScanner = fakeScanner
	mgr.ProcessKiller = fakeKiller

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	// All three non-harness descendants detected via cwd ownership.
	assert.Equal(t, int64(3), summary.StaleAttemptProcesses,
		"non-harness commands under stale worktree must be detected by cwd, not command name")
	assert.Len(t, summary.ProcessFindings, 3)
	for _, f := range summary.ProcessFindings {
		assert.Equal(t, staleWT, f.Worktree)
		assert.True(t, f.WouldKill)
	}

	fakeKiller.mu.Lock()
	assert.Empty(t, fakeKiller.killed, "dry-run must not kill")
	fakeKiller.mu.Unlock()
}

// TestExtractWorktreeFromCwd verifies the helper correctly extracts worktree paths.
func TestExtractWorktreeFromCwd(t *testing.T) {
	execRoot := "/tmp/exec-wt"
	prefix := ExecuteBeadWtPrefix + "ddx-abcd1234-20260611T000000-deadbeef"
	cases := []struct {
		cwd  string
		want string
	}{
		{filepath.Join(execRoot, prefix), filepath.Join(execRoot, prefix)},
		{filepath.Join(execRoot, prefix, "subdir"), filepath.Join(execRoot, prefix)},
		{filepath.Join(execRoot, prefix, "a", "b", "c"), filepath.Join(execRoot, prefix)},
		{execRoot, ""},
		{filepath.Join(execRoot, "plain-dir", "subdir"), ""},
		{"", ""},
		{execRoot + "other/foo", ""},
	}
	for _, tc := range cases {
		got := extractWorktreeFromCwd(tc.cwd, execRoot)
		assert.Equal(t, tc.want, got, "cwd=%q execRoot=%q", tc.cwd, execRoot)
	}
}

