50	// extractWorktreeFromCwd returns the DDx attempt worktree directory that
51	// contains cwd, or "" when cwd is not under a DDx attempt dir in execRoot.
52	func extractWorktreeFromCwd(cwd, execRoot string) string {
53		if cwd == "" || execRoot == "" {
54			return ""
55		}
56		cleanCwd := filepath.Clean(cwd)
57		cleanRoot := filepath.Clean(execRoot)
58		sep := string(filepath.Separator)
59		if !strings.HasPrefix(cleanCwd, cleanRoot+sep) {
60			return ""
61		}
62		rel := cleanCwd[len(cleanRoot)+len(sep):]
63		parts := strings.SplitN(rel, sep, 2)
64		if len(parts) == 0 || parts[0] == "" {
65			return ""
66		}
67		first := parts[0]
68		if !hasAnyPrefix(first, executionAttemptDirPrefixes()) {
69			return ""
70		}
71		return filepath.Join(cleanRoot, first)
72	}
