74	// ReapStaleAttemptDescendants reports and optionally kills processes under
75	// execRoot whose worktrees are no longer live. It is used by both the cleanup
76	// command and work startup to conservatively reap orphaned attempt-descendant
77	// processes. Non-fatal scan errors are surfaced as warnings in the summary.
78	func ReapStaleAttemptDescendants(
79		ctx context.Context,
80		execRoot string,
81		runStates []RunState,
82		registered map[string]struct{},
83		probe ExecutionCleanupLivenessProbe,
84		scanner AttemptDescendantScanner,
85		killer AttemptDescendantKiller,
86		dryRun bool,
87		now time.Time,
88		summary *ExecutionCleanupSummary,
89	) error {
90		return reapStaleAttemptDescendants(ctx, execRoot, runStates, registered, probe, scanner, killer, dryRun, now, summary)
91	}
