93	func reapStaleAttemptDescendants(
94		ctx context.Context,
95		execRoot string,
96		runStates []RunState,
97		registered map[string]struct{},
98		probe ExecutionCleanupLivenessProbe,
99		scanner AttemptDescendantScanner,
100		killer AttemptDescendantKiller,
101		dryRun bool,
102		now time.Time,
103		summary *ExecutionCleanupSummary,
104	) error {
105		if scanner == nil || execRoot == "" {
106			return nil
107		}
108		if ctx != nil && ctx.Err() != nil {
109			return ctx.Err()
110		}
111		if probe == nil {
112			probe = defaultExecutionCleanupLivenessProbe{}
113		}
114		if registered == nil {
115			registered = map[string]struct{}{}
116		}
117	
118		procs, err := scanner.ScanUnder(ctx, execRoot)
119		if err != nil {
120			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
121				Class:   "process_scan",
122				Message: err.Error(),
123			})
124			return nil // non-fatal: continue with file cleanup
125		}
126	
127		for _, proc := range procs {
128			if ctx != nil && ctx.Err() != nil {
129				return ctx.Err()
130			}
131			if proc.Worktree == "" {
132				continue
133			}
134			// Never touch a worktree that is still registered with git.
135			if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
136				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
137					Path:    proc.Worktree,
138					Class:   "preserved_process_registered_worktree",
139					Message: fmt.Sprintf("pid %d preserved: worktree is registered", proc.PID),
140				})
141				continue
142			}
143	
144			meta, metaErr := ReadExecutionCleanupMetadata(proc.Worktree)
145			if metaErr != nil {
146				if !errors.Is(metaErr, os.ErrNotExist) {
147					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
148						Path:    proc.Worktree,
149						Class:   "process_metadata_read",
150						Message: metaErr.Error(),
151					})
152					continue
153				}
154				meta = ExecutionCleanupMetadata{WorktreePath: proc.Worktree}
155			}
156			if meta.BeadID == "" {
157				meta.BeadID = proc.BeadID
158			}
159			if meta.AttemptID == "" {
160				meta.AttemptID = proc.AttemptID
161			}
162	
163			matchedRunState := matchingRunStateForMeta(runStates, meta)
164			live, reason := probe.IsLive(meta, matchedRunState, now)
165			if live {
166				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
167					Path:    proc.Worktree,
168					Class:   "preserved_process_live_worktree",
169					Message: fmt.Sprintf("pid %d preserved: %s", proc.PID, reason),
170				})
171				continue
172			}
173	
174			proc.StaleReason = reason
175			proc.WouldKill = true
176			summary.StaleAttemptProcesses++
177			summary.ProcessFindings = append(summary.ProcessFindings, proc)
178	
179			if dryRun {
180				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
181					Path:    proc.Worktree,
182					Class:   "would_reap_attempt_descendant",
183					Message: fmt.Sprintf("pid %d would be reaped: %s", proc.PID, reason),
184				})
185				continue
186			}
187	
188			if killer == nil {
189				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
190					Path:    proc.Worktree,
191					Class:   "process_no_killer",
192					Message: fmt.Sprintf("pid %d: no killer available on this platform", proc.PID),
193				})
194				continue
195			}
196			if killErr := killer.KillGroup(proc.PID); killErr != nil {
197				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
198					Path:    proc.Worktree,
199					Class:   "process_kill",
200					Message: fmt.Sprintf("failed to kill group %d: %v", proc.PID, killErr),
201				})
202			} else {
203				summary.ReapedAttemptProcesses++
204				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
205					Path:    proc.Worktree,
206					Class:   "reaped_attempt_descendant",
207					Message: fmt.Sprintf("pid %d reaped: %s", proc.PID, reason),
208				})
209			}
210		}
211		return nil
212	}
