156	func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
157		if meta.Preserved {
158			return true, "preserved metadata"
159		}
160		if meta.ActiveCandidateCycle {
161			return true, candidateCycleRecoveryReason(meta, "active candidate cycle")
162		}
163		if strings.TrimSpace(meta.CandidateRef) != "" {
164			return true, candidateCycleRecoveryReason(meta, "candidate ref recovery")
165		}
166		if runState != nil {
167			if strings.TrimSpace(runState.CandidateCyclePhase) != "" {
168				return true, candidateCycleRecoveryReason(candidateCycleMetadataFromRunState(*runState), "active candidate cycle")
169			}
170			if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
171				return true, "matched live run-state"
172			}
173			if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
174				return true, "matched live run-state"
175			}
176		}
177		if meta.Liveness != nil {
178			if meta.Liveness.PID > 0 && trackerProcessAlive(meta.Liveness.PID) {
179				return true, "live pid"
180			}
181			if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
182				return true, "unexpired liveness"
183			}
184			if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
185				return true, "fresh liveness"
186			}
187		}
188		return false, "stale liveness"
189	}
