// TestCleanupCommand_JSONIncludesProcessFindings proves the JSON output includes
// process census fields (stale_attempt_processes, reaped_attempt_processes,
// process_findings) without breaking existing fields (AC3).
func TestCleanupCommand_JSONIncludesProcessFindings(t *testing.T) {
	projectRoot, _ := setupCleanupCommandProject(t)

	root := NewCommandFactory(projectRoot).NewRootCommand()
	out, err := executeCommand(root, "cleanup", "--json")
	require.NoError(t, err)

	var report cleanupCommandJSON
	require.NoError(t, json.Unmarshal([]byte(out), &report), "JSON must be valid")

	// Existing fields must still be present and correctly typed.
	assert.True(t, report.DryRun)
	assert.NotEmpty(t, report.ProjectRoot)
	assert.NotNil(t, report.Warnings)
	assert.NotNil(t, report.BlockedErrors)
	assert.NotNil(t, report.Observations)

	// New process census fields must be present (zero value is valid when no stale processes found).
	assert.GreaterOrEqual(t, report.StaleAttemptProcesses, int64(0))
	assert.GreaterOrEqual(t, report.ReapedAttemptProcesses, int64(0))
	// process_findings must be an empty array, not null/absent.
	assert.NotNil(t, report.ProcessFindings,
