type fakeStartupScanner struct {
	procs []agent.AttemptDescendantProcess
}

func (f *fakeStartupScanner) ScanUnder(_ context.Context, _ string) ([]agent.AttemptDescendantProcess, error) {
	return append([]agent.AttemptDescendantProcess(nil), f.procs...), nil
}

// fakeStartupKiller records which PIDs were killed.
type fakeStartupKiller struct {
