// TestWorkStartupCleanup_ReapsStaleAttemptDescendantProcessesBeforeClaim proves
// that work startup cleanup reaps stale attempt descendant processes (AC4).
// The process scan happens as part of startup housekeeping, before any bead is claimed.
func TestWorkStartupCleanup_ReapsStaleAttemptDescendantProcessesBeforeClaim(t *testing.T) {
	projectRoot := setupWorkStartupCleanupProjectRoot(t)

	tempRoot := filepath.Join(t.TempDir(), "exec-wt")
	require.NoError(t, os.MkdirAll(tempRoot, 0o755))

	// Create a stale worktree with metadata but no live run-state/liveness.
	beadID := "ddx-startup-orphan"
	attemptID := "20260611T020000-aabbccdd"
	staleWT := filepath.Join(tempRoot, agent.ExecuteBeadWtPrefix+beadID+"-"+attemptID)
	require.NoError(t, os.MkdirAll(staleWT, 0o755))
	require.NoError(t, agent.WriteExecutionCleanupMetadata(staleWT, agent.ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       beadID,
		AttemptID:    attemptID,
		WorktreePath: staleWT,
	}))

	scanner := &fakeStartupScanner{
		procs: []agent.AttemptDescendantProcess{
			{PID: 5555, PGID: 5555, Command: "sh -c cargo test", Cwd: staleWT, Worktree: staleWT},
		},
	}
	killer := &fakeStartupKiller{}

	runner := newStartupHousekeepingRunner(projectRoot)
	runner.tempRoot = tempRoot
	runner.processScanner = scanner
	runner.processKiller = killer

	report, err := runner.scan(context.Background(), true)
	require.NoError(t, err)

	assert.Equal(t, int64(1), report.StaleAttemptProcesses,
		"startup cleanup must detect stale attempt descendant processes")
	assert.Equal(t, int64(1), report.ReapedAttemptProcesses,
		"startup cleanup must reap stale attempt descendant processes")
	require.Equal(t, []int{5555}, killer.killed,
		"killer must have been called with the stale process PID before any bead claim")
}

